                    parent[rootX] = rootY;
                } else {
                    parent[rootY] = rootX;
                    rank[rootX]++;
                }
            }
        }

        // Preprocess the graph to find the minimum node in each connected component
        Map<Integer, Integer> minNodeInComponent = new HashMap<>();
        for (int i = 1; i <= numNodes; i++) {
